      prisma.$queryRaw<DailyTransactionQueryRow[]>`
        SELECT
          cpa.partyType AS partyType,
          c.id AS caseId,
          c.shortId AS shortId,
          c.disputeReferenceNumber AS disputeReferenceNumber,
          p.amount AS amount,
          p.type AS paymentType,
