function extractPayee(payment) {
      let payee = '';
      try {
        if (payment.bankingSnapshot) {
          const snap = typeof payment.bankingSnapshot === 'string'
            ? JSON.parse(payment.bankingSnapshot)
            : payment.bankingSnapshot;
          if (snap && snap.accountHolderName) payee = snap.accountHolderName;
        }
      } catch {}
      return payee || payment.recipientName || '';
    }

    function formatDateEST(date) {
      const options = {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
        timeZone: 'America/New_York',
      };
      const formatted = new Intl.DateTimeFormat('en-US', options).format(date);
      return `${formatted} EST`;
    }

    const allowedPayees = ['halo', 'veratru', 'capitol bridge'];
    const cases = payments.flatMap((payment) => {
      const payee = extractPayee(payment);
      if (!allowedPayees.includes((payee || '').toLowerCase())) return [];
      return payment.caseAllocations.map((allocation) => {
        const caseData = allocation.case;
        if (!caseData) return null;

        const lineItemCount = caseData.DisputeLineItems?.length || 1;
        const disputeType = caseData.typeOfDispute;

        let entityFeePerPartyCents = 0;

        const isAdministrativeClosure =
          caseData.status === CaseStatus.PENDING_CLOSURE_PAYMENTS ||
          caseData.status === CaseStatus.PENDING_ADMINISTRATIVE_CLOSURE ||
          caseData.status === CaseStatus.CLOSED_ADMINISTRATIVE;

        const isSettlementOrWithdrawal = [
          "SETTLEMENT",
          "WITHDRAWAL",
          "WITHDRAWAL_IP",
          "WITHDRAWAL_NIP",
        ].includes(caseData.closure_reason || "");

        const isIneligibleCase =
          caseData.status === CaseStatus.INELIGIBLE ||
          caseData.status === CaseStatus.INELIGIBLE_PENDING_ADMIN_FEE;

        const isNonPaymentDismissal =
          caseData.status === CaseStatus.NOTICE_OF_DISMISSAL_NON_PAYMENT ||
          (caseData.status === CaseStatus.CLOSED_ADMINISTRATIVE &&
            caseData.closure_reason === "DISMISSAL_NON_PAYMENT_BOTH");

        if (isIneligibleCase || isNonPaymentDismissal) {
          entityFeePerPartyCents = 0;
        } else {
          if (disputeType === "SINGLE") {
            entityFeePerPartyCents = CASE_PRICING.SINGLE.ENTITY_FEE;
          } else if (disputeType === "BUNDLED") {
            entityFeePerPartyCents = CASE_PRICING.BUNDLED.ENTITY_FEE;
          } else if (disputeType === "BATCHED") {
            entityFeePerPartyCents = CASE_PRICING.BATCHED.ENTITY_FEE;
            if (lineItemCount > 25) {
              const additionalGroups = Math.ceil((lineItemCount - 25) / 25);
              entityFeePerPartyCents +=
                additionalGroups * CASE_PRICING.BATCHED.SURCHARGE_PER_25_ITEMS;
            }
          }

          if (isAdministrativeClosure && isSettlementOrWithdrawal) {
            entityFeePerPartyCents = Math.round(entityFeePerPartyCents / 2);
          }
        }

        const entityFeePerParty = (entityFeePerPartyCents / 100).toFixed(2);

        return {
          Payee: payee,
          "Dispute ID": caseData.disputeReferenceNumber || '',
          "Dispute Status": caseData.status?.replace(/_/g, " ") || '',
          "Date Decision Rendered": caseData.decision_date
            ? new Date(caseData.decision_date).toLocaleDateString("en-US")
            : "N/A",
          "Date Dispute Closed": caseData.closed_at
            ? new Date(caseData.closed_at).toLocaleDateString("en-US")
            : "N/A",
          "Entity Fee Paid Per Party": `$${entityFeePerParty}`,
          "Date Payment Completed": formatDateEST(payment.processedAt || payment.paidAt || payment.updatedAt || payment.createdAt),
        };
      }).filter(Boolean);
    });

