function latestIncomingPaymentStatus(allocations, party) {
  const relevant = allocations
    .filter(
      (a) =>
        a.partyType === party &&
        a.payment &&
        a.payment.direction === "INCOMING"
    )
    .map((a) => a.payment)
    .filter(Boolean)
    .sort(
      (a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );

  return relevant[0]?.status ?? null;
}

function isPartyPaid(status) {
  if (!status) return false;
  return ["PENDING", "APPROVED", "COMPLETED"].includes(status);
}

function calculatePaymentDueDate(createdAt) {
  const dueDate = new Date(createdAt);
  let businessDays = 0;

  while (businessDays < 30) {
    dueDate.setDate(dueDate.getDate() + 1);
    const dayOfWeek = dueDate.getDay();
    if (dayOfWeek !== 0 && dayOfWeek !== 6) {
      businessDays++;
    }
  }
  return dueDate;
}

// from lib/constants/pricing.ts
function calculateCasePaymentAmount(caseType, lineItemCount) {
  const baseFee = caseType === 'SINGLE' ? 10000 : 20000;
  const additionalFee = lineItemCount > 1 ? (lineItemCount - 1) * 2500 : 0;
  return baseFee + additionalFee;
}

const rows = cases
  .flatMap((c) => {
    const ipStatus = latestIncomingPaymentStatus(c.paymentAllocations, "INITIATING");
    const nipStatus = latestIncomingPaymentStatus(c.paymentAllocations, "NON_INITIATING");

    const ipPaid = isPartyPaid(ipStatus);
    const nipPaid = isPartyPaid(nipStatus);

    if (ipPaid && nipPaid) return [];

    const caseType = c.typeOfDispute || "BUNDLED";
    const lineItemCount = c.DisputeLineItems?.length || 1;
    const amountDueCents = calculateCasePaymentAmount(caseType, lineItemCount);
    const amountDue = amountDueCents / 100;
    const paymentDueDate = calculatePaymentDueDate(c.createdAt);

    return [{
      caseId: c.id,
      disputeId: c.disputeReferenceNumber || c.id,
      dateOpened: c.createdAt.toISOString(),
      paymentDueDate: paymentDueDate.toISOString(),
      nipOrganizationName: c.nonInitiatingPartyOrganization?.name || "N/A",
      nipOrganizationId: c.nonInitiatingPartyOrganization?.id || "N/A",
      nipEmails: [
        ...(c.nonInitiatingPartyOrganization?.email ? [c.nonInitiatingPartyOrganization.email] : []),
        ...(c.nonInitiatingPartyOrganization?.members
          ?.map((m) => usersById.get(m.userId))
          .filter((email) => Boolean(email)) || []),
      ].filter((email, index, self) => email && self.indexOf(email) === index),
      ipOrganizationName: c.initiatingPartyOrganization?.name || "N/A",
      ipOrganizationId: c.initiatingPartyOrganization?.id || "N/A",
      ipEmails: [
        ...(c.initiatingPartyOrganization?.email ? [c.initiatingPartyOrganization.email] : []),
        ...(c.initiatingPartyOrganization?.members
          ?.map((m) => usersById.get(m.userId))
          .filter((email) => Boolean(email)) || []),
      ].filter((email, index, self) => email && self.indexOf(email) === index),
      ipPaymentReceived: ipPaid,
      nipPaymentReceived: nipPaid,
      amountDue,
      status: c.status,
    }];
  })
  .filter((row) => {
    if (!searchTerm) {
      return true;
    }
    return (
      row.disputeId.toLowerCase().includes(searchTerm) ||
      row.ipOrganizationName.toLowerCase().includes(searchTerm) ||
      row.nipOrganizationName.toLowerCase().includes(searchTerm) ||
      row.ipEmails.some((email) => email.toLowerCase().includes(searchTerm)) ||
