function latestIncomingPaymentStatus(allocations: any[], party: PartyType): string | null {
  const relevant = allocations
    .filter(
      (a: any) =>
        a.partyType === party &&
        a.payment &&
        a.payment.direction === "INCOMING"
    )
    .map((a: any) => a.payment)
    .filter(Boolean)
    .sort(
      (a: any, b: any) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );

  return relevant[0]?.status ?? null;
}

function isPartyPaid(status: string | null): boolean {
  if (!status) return false;
  return ["PENDING", "APPROVED", "COMPLETED"].includes(status);
}

